{
  "name": "Yuanware Calc v2.0",
  "description": "A high-performance calculation suite for streetwear importers. Features smart freight distribution, tax weighting, and AI-driven strategic analysis."
}

export interface ProductItem {
  id: string;
  name: string;
  priceYuan: number;
  quantity: number;
}

export interface CalculatedItem extends ProductItem {
  distributedFreightBRL: number;
  distributedTaxBRL: number;
  totalCostBRL: number;
  suggestedPriceBRL: number;
  profitBRL: number;
}

export interface PackageData {
  items: ProductItem[];
  totalFreightYuan: number;
  totalTaxBRL: number;
  exchangeRate: number;
}

export interface AnalysisResult {
  totalInvestmentBRL: number;
  totalRevenueBRL: number;
  totalProfitBRL: number;
  roi: number;
  verdict: 'GEM' | 'HEALTHY' | 'RISKY';
  items: CalculatedItem[];
}

export interface ChatMessage {
  role: 'user' | 'model';
  content: string;
}

export const COLORS = {
  BLACK: '#000000',
  PURPLE: '#bc13fe',
  GREEN: '#00ff41',
  RED: '#ff003c',
  CREAM: '#FFFDD0',
};

export const DEFAULT_EXCHANGE_RATE = 0.85; // Adjusted for spread

import { GoogleGenAI } from "@google/genai";
import { AnalysisResult, ChatMessage } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getStrategicAnalysis = async (
  analysis: AnalysisResult,
  history: ChatMessage[]
): Promise<string> => {
  const model = 'gemini-3-flash-preview';

  const systemInstruction = `
    Você é o consultor de importação "YUANWARE AI", especialista em Streetwear e logística China-Brasil.
    Sua personalidade é direta, profissional, agressiva mas cautelosa, focada em ROI e viabilidade de mercado.

    Contexto da Importação Atual:
    - Investimento Total: R$ ${analysis.totalInvestmentBRL.toFixed(2)}
    - Lucro Previsto: R$ ${analysis.totalProfitBRL.toFixed(2)}
    - ROI: ${analysis.roi.toFixed(2)}%
    - Itens: ${analysis.items.map(i => `${i.name} (Qtde: ${i.quantity})`).join(', ')}

    Responda em Português do Brasil. Use termos de importação como "desembaraço", "spread", "lastro", "hype".
    Seja honesto se o pacote compensa ou não. Se o ROI estiver baixo, seja crítico.
  `;

  const contents = history.map(msg => ({
    role: msg.role,
    parts: [{ text: msg.content }]
  }));

  try {
    const response = await ai.models.generateContent({
      model,
      contents: contents as any,
      config: {
        systemInstruction,
        temperature: 0.7,
      },
    });

    return response.text || "Sem resposta do servidor.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Erro ao processar consultoria estratégica.";
  }
};

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useCallback, useMemo, useRef } from 'react';
import { Plus, Trash2, LayoutDashboard, Calculator, Receipt, RotateCcw, MessageSquare, Send, Bot, AlertTriangle, ShieldCheck, Diamond } from 'lucide-react';
import html2canvas from 'html2canvas';
import { ProductItem, PackageData, AnalysisResult, CalculatedItem, ChatMessage } from './types';
import { COLORS, DEFAULT_EXCHANGE_RATE } from './constants';
import { getStrategicAnalysis } from './services/geminiService';

const App: React.FC = () => {
  const [items, setItems] = useState<ProductItem[]>([
    { id: '1', name: '', priceYuan: 0, quantity: 1 }
  ]);
  const [freight, setFreight] = useState<number>(0);
  const [tax, setTax] = useState<number>(0);
  const [rate, setRate] = useState<number>(DEFAULT_EXCHANGE_RATE);
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [userInput, setUserInput] = useState('');
  const [chatLoading, setChatLoading] = useState(false);

  const ticketRef = useRef<HTMLDivElement>(null);

  const addItem = () => {
    setItems([...items, { id: Math.random().toString(36).substr(2, 9), name: '', priceYuan: 0, quantity: 1 }]);
  };

  const removeItem = (id: string) => {
    setItems(items.filter(item => item.id !== id));
  };

  const updateItem = (id: string, field: keyof ProductItem, value: string | number) => {
    setItems(items.map(item => item.id === id ? { ...item, [field]: value } : item));
  };

  const processRounding = (price: number): number => {
    // Rounding logic: ending in 7 or 0 (rounding up)
    const ceilVal = Math.ceil(price);
    const lastDigit = ceilVal % 10;

    if (lastDigit === 0) return ceilVal;
    if (lastDigit < 7) {
      return Math.floor(ceilVal / 10) * 10 + 7;
    }
    return Math.ceil(ceilVal / 10) * 10;
  };

  const processData = () => {
    setLoading(true);

    const totalItemsValueYuan = items.reduce((acc, item) => acc + (item.priceYuan * item.quantity), 0);

    const calculatedItems: CalculatedItem[] = items.map(item => {
      const itemTotalPriceYuan = item.priceYuan * item.quantity;
      const weight = totalItemsValueYuan > 0 ? (itemTotalPriceYuan / totalItemsValueYuan) : 0;

      const itemFreightYuan = weight * freight;
      const itemTaxBRL = weight * tax;

      const itemCostBRL = ((item.priceYuan + (itemFreightYuan / item.quantity)) * rate) + (itemTaxBRL / item.quantity);
      const suggestedPrice = processRounding(itemCostBRL * 2);
      const profit = suggestedPrice - itemCostBRL;

      return {
        ...item,
        distributedFreightBRL: (itemFreightYuan / item.quantity) * rate,
        distributedTaxBRL: itemTaxBRL / item.quantity,
        totalCostBRL: itemCostBRL,
        suggestedPriceBRL: suggestedPrice,
        profitBRL: profit
      };
    });

    const totalInvestment = calculatedItems.reduce((acc, item) => acc + (item.totalCostBRL * item.quantity), 0);
    const totalRevenue = calculatedItems.reduce((acc, item) => acc + (item.suggestedPriceBRL * item.quantity), 0);
    const totalProfit = totalRevenue - totalInvestment;
    const roi = totalInvestment > 0 ? (totalProfit / totalInvestment) * 100 : 0;

    let verdict: 'GEM' | 'HEALTHY' | 'RISKY' = 'RISKY';
    if (roi > 100) verdict = 'GEM';
    else if (roi >= 50) verdict = 'HEALTHY';

    setAnalysis({
      totalInvestmentBRL: totalInvestment,
      totalRevenueBRL: totalRevenue,
      totalProfitBRL: totalProfit,
      roi,
      verdict,
      items: calculatedItems
    });

    setLoading(false);
  };

  const handleGenerateTicket = async () => {
    if (!ticketRef.current) return;
    try {
      const canvas = await html2canvas(ticketRef.current, { backgroundColor: '#000000' });
      const link = document.createElement('a');
      link.download = `yuanware_ticket_${Date.now()}.png`;
      link.href = canvas.toDataURL();
      link.click();
    } catch (err) {
      console.error('Failed to generate ticket', err);
    }
  };

  const sendMessage = async () => {
    if (!userInput.trim() || !analysis) return;

    const userMsg: ChatMessage = { role: 'user', content: userInput };
    const newHistory = [...chatHistory, userMsg];
    setChatHistory(newHistory);
    setUserInput('');
    setChatLoading(true);

    try {
      const aiResponse = await getStrategicAnalysis(analysis, newHistory);
      setChatHistory([...newHistory, { role: 'model', content: aiResponse }]);
    } catch (err) {
      console.error(err);
    } finally {
      setChatLoading(false);
    }
  };

  const resetAll = () => {
    setAnalysis(null);
    setChatHistory([]);
    setItems([{ id: '1', name: '', priceYuan: 0, quantity: 1 }]);
    setFreight(0);
    setTax(0);
  };

  return (
    <div className="min-h-screen flex flex-col items-center p-4 md:p-8 space-y-8 bg-black">
      {/* Header */}
      <header className="w-full max-w-5xl flex flex-col items-center justify-center py-6 border-b border-zinc-800">
        <h1 className="text-3xl md:text-5xl font-bold neon-purple tracking-tighter">
          YUANWARE_CALC <span className="text-zinc-500 text-sm md:text-xl">v2.0</span>
        </h1>
        <p className="text-zinc-400 mt-2 text-xs md:text-sm">ESTABLISHED IN THE HUSTLE // STREETWEAR IMPORT SUITE</p>
      </header>

      <main className="w-full max-w-5xl grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Input Side */}
        <div className="lg:col-span-5 space-y-6">
          <section className="bg-zinc-900/50 p-6 rounded-lg border border-zinc-800 neon-purple-border">
            <h2 className="text-xl font-bold mb-6 flex items-center gap-2">
              <Plus className="neon-purple" /> ENTRADA DE DADOS
            </h2>

            <div className="space-y-4">
              {items.map((item, idx) => (
                <div key={item.id} className="grid grid-cols-12 gap-2 pb-4 border-b border-zinc-800">
                  <div className="col-span-12 md:col-span-5">
                    <label className="text-[10px] text-zinc-500 uppercase">Produto</label>
                    <input
                      type="text"
                      placeholder="EX: AJ1 LOW REVERSE"
                      className="w-full bg-black border border-zinc-800 p-2 text-xs text-white"
                      value={item.name}
                      onChange={(e) => updateItem(item.id, 'name', e.target.value)}
                    />
                  </div>
                  <div className="col-span-5 md:col-span-3">
                    <label className="text-[10px] text-zinc-500 uppercase">Preço (¥)</label>
                    <input
                      type="number"
                      placeholder="¥"
                      className="w-full bg-black border border-zinc-800 p-2 text-xs text-white"
                      value={item.priceYuan || ''}
                      onChange={(e) => updateItem(item.id, 'priceYuan', Number(e.target.value))}
                    />
                  </div>
                  <div className="col-span-4 md:col-span-2">
                    <label className="text-[10px] text-zinc-500 uppercase">Qtde</label>
                    <input
                      type="number"
                      placeholder="QTY"
                      className="w-full bg-black border border-zinc-800 p-2 text-xs text-white"
                      value={item.quantity || ''}
                      onChange={(e) => updateItem(item.id, 'quantity', Number(e.target.value))}
                    />
                  </div>
                  <div className="col-span-3 md:col-span-2 flex items-end">
                    <button 
                      onClick={() => removeItem(item.id)}
                      className="w-full h-[34px] bg-zinc-900 border border-zinc-800 hover:bg-red-900/20 hover:border-red-500 flex items-center justify-center transition-all"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                </div>
              ))}
            </div>

            <button 
              onClick={addItem}
              className="mt-6 w-full py-2 border border-dashed border-zinc-700 text-zinc-500 hover:text-white hover:border-white transition-all text-xs flex items-center justify-center gap-2"
            >
              <Plus size={14} /> ADICIONAR ITEM (+)
            </button>
          </section>

          {/* Logistics */}
          <section className="bg-zinc-900/50 p-6 rounded-lg border border-zinc-800">
             <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-xs text-zinc-500 uppercase mb-2 block">Frete Total (¥)</label>
                  <input
                    type="number"
                    placeholder="¥"
                    className="w-full bg-black border border-zinc-800 p-3 text-sm text-white font-bold"
                    value={freight || ''}
                    onChange={(e) => setFreight(Number(e.target.value))}
                  />
                </div>
                <div>
                  <label className="text-xs text-zinc-500 uppercase mb-2 block">Cotação (R$)</label>
                  <input
                    type="number"
                    step="0.01"
                    placeholder="0.85"
                    className="w-full bg-black border border-zinc-800 p-3 text-sm text-white font-bold"
                    value={rate}
                    onChange={(e) => setRate(Number(e.target.value))}
                  />
                </div>
                <div className="col-span-2">
                  <label className="text-xs text-zinc-500 uppercase mb-2 block">Taxas Extras (R$)</label>
                  <input
                    type="number"
                    placeholder="R$ VALOR TOTAL DE TAXAS"
                    className="w-full bg-black border border-zinc-800 p-3 text-sm text-white font-bold"
                    value={tax || ''}
                    onChange={(e) => setTax(Number(e.target.value))}
                  />
                </div>
             </div>

             <button 
              onClick={processData}
              disabled={loading}
              className="mt-8 w-full bg-white text-black font-black py-4 hover:bg-purple-600 hover:text-white transition-all flex items-center justify-center gap-3"
            >
              <Calculator size={20} /> PROCESSAR DADOS
            </button>
          </section>
        </div>

        {/* Output Side */}
        <div className="lg:col-span-7 space-y-6">
          {analysis ? (
            <div className="space-y-6 animate-in fade-in duration-500">

              {/* Verdict Card */}
              <div className={`p-6 border-2 flex items-center justify-between rounded-lg ${
                analysis.verdict === 'GEM' ? 'border-[#00ff41] bg-[#00ff41]/5' : 
                analysis.verdict === 'HEALTHY' ? 'border-yellow-400 bg-yellow-400/5' : 
                'border-[#ff003c] bg-[#ff003c]/5'
              }`}>
                <div className="flex items-center gap-4">
                  {analysis.verdict === 'GEM' && <Diamond size={32} className="neon-green pulse" />}
                  {analysis.verdict === 'HEALTHY' && <ShieldCheck size={32} className="text-yellow-400" />}
                  {analysis.verdict === 'RISKY' && <AlertTriangle size={32} className="neon-red" />}
                  <div>
                    <h3 className={`text-xl font-black uppercase ${
                      analysis.verdict === 'GEM' ? 'neon-green' : 
                      analysis.verdict === 'HEALTHY' ? 'text-yellow-400' : 
                      'neon-red'
                    }`}>
                      {analysis.verdict === 'GEM' ? '💎 GEM DETECTED: MINA DE OURO!' : 
                       analysis.verdict === 'HEALTHY' ? '✅ MARGEM SAUDÁVEL. PODE IMPORTAR.' : 
                       '⚠️ ALERTA: MARGEM APERTADA. REAVALIE.'}
                    </h3>
                    <p className="text-[10px] text-zinc-400">VEREDITO ESTRATÉGICO YUANWARE</p>
                  </div>
                </div>
                <div className="text-right">
                  <p className="text-2xl font-black">{analysis.roi.toFixed(1)}%</p>
                  <p className="text-[10px] text-zinc-500 uppercase">ROI ESTIMADO</p>
                </div>
              </div>

              {/* Summary Cards */}
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="bg-zinc-900 border border-zinc-800 p-4 rounded-lg">
                  <p className="text-[10px] text-zinc-500 uppercase">Investimento Total</p>
                  <p className="text-lg font-bold">R$ {analysis.totalInvestmentBRL.toLocaleString()}</p>
                </div>
                <div className="bg-zinc-900 border border-zinc-800 p-4 rounded-lg">
                  <p className="text-[10px] text-zinc-500 uppercase">Faturamento</p>
                  <p className="text-lg font-bold">R$ {analysis.totalRevenueBRL.toLocaleString()}</p>
                </div>
                <div className="bg-zinc-900 border border-zinc-800 p-4 rounded-lg">
                  <p className="text-[10px] text-zinc-500 uppercase">Lucro Líquido</p>
                  <p className="text-lg font-bold neon-purple">R$ {analysis.totalProfitBRL.toLocaleString()}</p>
                </div>
              </div>

              {/* Detailed Table */}
              <div className="bg-zinc-900 border border-zinc-800 rounded-lg overflow-hidden">
                <div className="overflow-x-auto">
                  <table className="w-full text-left text-xs">
                    <thead>
                      <tr className="bg-zinc-800 text-zinc-400 uppercase">
                        <th className="p-4">Item</th>
                        <th className="p-4">Qtde</th>
                        <th className="p-4">Custo Unit.</th>
                        <th className="p-4">Sugestão Venda</th>
                        <th className="p-4">Lucro/Un.</th>
                      </tr>
                    </thead>
                    <tbody>
                      {analysis.items.map((item, i) => (
                        <tr key={i} className="border-b border-zinc-800 hover:bg-zinc-800/30">
                          <td className="p-4 font-bold">{item.name || 'SEM NOME'}</td>
                          <td className="p-4">{item.quantity}</td>
                          <td className="p-4 text-zinc-400">R$ {item.totalCostBRL.toFixed(2)}</td>
                          <td className="p-4 font-bold text-white">R$ {item.suggestedPriceBRL.toFixed(2)}</td>
                          <td className="p-4 neon-purple font-bold">R$ {item.profitBRL.toFixed(2)}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>

              {/* AI Chat Section */}
              <div className="bg-zinc-900/80 border border-zinc-800 rounded-lg overflow-hidden flex flex-col">
                <div className="bg-zinc-800 p-3 flex items-center gap-2">
                  <Bot size={18} className="neon-purple" />
                  <span className="text-xs font-bold uppercase tracking-widest">YUANWARE AI CONSULTOR</span>
                </div>
                <div className="h-64 overflow-y-auto p-4 space-y-4 text-xs">
                  {chatHistory.length === 0 && (
                    <div className="h-full flex flex-col items-center justify-center text-zinc-600 text-center">
                      <MessageSquare size={32} className="mb-2 opacity-20" />
                      <p>Dúvidas sobre esse pacote?<br/>O consultor está pronto para analisar.</p>
                    </div>
                  )}
                  {chatHistory.map((msg, i) => (
                    <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                      <div className={`max-w-[80%] p-3 rounded-lg ${msg.role === 'user' ? 'bg-zinc-800' : 'bg-purple-900/20 border border-purple-500/30'}`}>
                        {msg.content}
                      </div>
                    </div>
                  ))}
                  {chatLoading && <div className="text-zinc-500 animate-pulse">Pensando estrategicamente...</div>}
                </div>
                <div className="p-3 border-t border-zinc-800 flex gap-2">
                  <input
                    type="text"
                    placeholder="Pergunte sobre rentabilidade, frete ou mercado..."
                    className="flex-1 bg-black border border-zinc-800 p-2 text-xs"
                    value={userInput}
                    onChange={(e) => setUserInput(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && sendMessage()}
                  />
                  <button 
                    onClick={sendMessage}
                    disabled={chatLoading}
                    className="bg-purple-600 p-2 rounded hover:bg-purple-500 transition-colors"
                  >
                    <Send size={16} />
                  </button>
                </div>
              </div>

              {/* Footer Actions */}
              <div className="flex flex-col md:flex-row gap-4">
                <button 
                  onClick={handleGenerateTicket}
                  className="flex-1 bg-zinc-900 border-2 border-white text-white font-black py-4 hover:bg-white hover:text-black transition-all flex items-center justify-center gap-3"
                >
                  <Receipt size={20} /> GERAR TICKET YUANWARE 📸
                </button>
                <button 
                  onClick={resetAll}
                  className="bg-black border border-zinc-800 text-zinc-500 px-6 py-4 hover:text-red-500 hover:border-red-500 transition-all flex items-center justify-center gap-2"
                >
                  <RotateCcw size={18} /> REINICIAR
                </button>
              </div>

            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center text-zinc-800 text-center space-y-4 opacity-50">
              <LayoutDashboard size={64} />
              <div>
                <h3 className="text-xl font-bold">AGUARDANDO DADOS...</h3>
                <p className="text-xs">Insira os itens e custos para desbloquear o dashboard.</p>
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Hidden Ticket Template */}
      <div style={{ position: 'absolute', left: '-9999px', top: '0' }}>
        <div 
          ref={ticketRef} 
          className="w-[400px] bg-black p-8 border-4 border-white flex flex-col items-center text-white"
        >
          <div className="w-full text-center border-b border-dashed border-white pb-6 mb-6">
            <h1 className="text-3xl font-black tracking-tighter mb-1">YUANWARE_CALC</h1>
            <p className="text-[10px] opacity-60">STREETWEAR LOGISTICS V2.0</p>
          </div>

          <div className="w-full space-y-6 ticket-font">
            <div className="flex justify-between items-end border-b border-zinc-800 pb-4">
              <span className="text-[10px] opacity-60">INVESTIMENTO TOTAL</span>
              <span className="text-xl font-bold">R$ {analysis?.totalInvestmentBRL.toFixed(2)}</span>
            </div>
            <div className="flex justify-between items-end border-b border-zinc-800 pb-4">
              <span className="text-[10px] opacity-60">LUCRO PREVISTO</span>
              <span className="text-xl font-bold neon-purple">R$ {analysis?.totalProfitBRL.toFixed(2)}</span>
            </div>
            <div className="flex justify-between items-end border-b border-zinc-800 pb-4">
              <span className="text-[10px] opacity-60">ROI DA MALA</span>
              <span className="text-xl font-bold">{analysis?.roi.toFixed(1)}%</span>
            </div>
          </div>

          <div className="mt-12 w-full text-center space-y-4">
            <div className="py-2 border-y border-white">
               <p className="text-xs font-black tracking-widest italic">{analysis?.verdict === 'GEM' ? '💎 MINA DE OURO DETECTADA' : '🔥 HYPE SECURED'}</p>
            </div>
            <p className="text-[10px] neon-purple tracking-[0.3em] font-bold">🔥 powered by yuanware</p>
            <p className="text-[8px] opacity-30 uppercase">{new Date().toLocaleString()}</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

export const COLORS = {
  BLACK: '#000000',
  CREAM: '#FDFCF5',
  RED: '#D0021B',
  ZINC: '#71717a',
};

export const DEFAULT_EXCHANGE_RATE = 0.85;

import React, { useState, useCallback, useMemo, useRef } from 'react';
import { Plus, Trash2, LayoutDashboard, Calculator, Receipt, RotateCcw, MessageSquare, Send, Bot, AlertTriangle, ShieldCheck, Diamond, ArrowRight } from 'lucide-react';
import html2canvas from 'html2canvas';
import { ProductItem, AnalysisResult, CalculatedItem, ChatMessage } from './types';
import { COLORS, DEFAULT_EXCHANGE_RATE } from './constants';
import { getStrategicAnalysis } from './services/geminiService';

const App: React.FC = () => {
  const [items, setItems] = useState<ProductItem[]>([
    { id: '1', name: '', priceYuan: 0, quantity: 1 }
  ]);
  const [freight, setFreight] = useState<number>(0);
  const [tax, setTax] = useState<number>(0);
  const [rate, setRate] = useState<number>(DEFAULT_EXCHANGE_RATE);
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [userInput, setUserInput] = useState('');
  const [chatLoading, setChatLoading] = useState(false);

  const ticketRef = useRef<HTMLDivElement>(null);

  const addItem = () => {
    setItems([...items, { id: Math.random().toString(36).substr(2, 9), name: '', priceYuan: 0, quantity: 1 }]);
  };

  const removeItem = (id: string) => {
    if (items.length > 1) {
      setItems(items.filter(item => item.id !== id));
    }
  };

  const updateItem = (id: string, field: keyof ProductItem, value: string | number) => {
    setItems(items.map(item => item.id === id ? { ...item, [field]: value } : item));
  };

  const processRounding = (price: number): number => {
    const ceilVal = Math.ceil(price);
    const lastDigit = ceilVal % 10;
    if (lastDigit === 0) return ceilVal;
    if (lastDigit < 7) return Math.floor(ceilVal / 10) * 10 + 7;
    return Math.ceil(ceilVal / 10) * 10;
  };

  const processData = () => {
    setLoading(true);
    const totalItemsValueYuan = items.reduce((acc, item) => acc + (item.priceYuan * item.quantity), 0);

    const calculatedItems: CalculatedItem[] = items.map(item => {
      const itemTotalPriceYuan = item.priceYuan * item.quantity;
      const weight = totalItemsValueYuan > 0 ? (itemTotalPriceYuan / totalItemsValueYuan) : 0;

      const itemFreightYuan = weight * freight;
      const itemTaxBRL = weight * tax;

      const itemCostBRL = ((item.priceYuan + (itemFreightYuan / item.quantity)) * rate) + (itemTaxBRL / item.quantity);
      const suggestedPrice = processRounding(itemCostBRL * 2);
      const profit = suggestedPrice - itemCostBRL;

      return {
        ...item,
        distributedFreightBRL: (itemFreightYuan / item.quantity) * rate,
        distributedTaxBRL: itemTaxBRL / item.quantity,
        totalCostBRL: itemCostBRL,
        suggestedPriceBRL: suggestedPrice,
        profitBRL: profit
      };
    });

    const totalInvestment = calculatedItems.reduce((acc, item) => acc + (item.totalCostBRL * item.quantity), 0);
    const totalRevenue = calculatedItems.reduce((acc, item) => acc + (item.suggestedPriceBRL * item.quantity), 0);
    const totalProfit = totalRevenue - totalInvestment;
    const roi = totalInvestment > 0 ? (totalProfit / totalInvestment) * 100 : 0;

    let verdict: 'GEM' | 'HEALTHY' | 'RISKY' = 'RISKY';
    if (roi > 100) verdict = 'GEM';
    else if (roi >= 50) verdict = 'HEALTHY';

    setAnalysis({
      totalInvestmentBRL: totalInvestment,
      totalRevenueBRL: totalRevenue,
      totalProfitBRL: totalProfit,
      roi,
      verdict,
      items: calculatedItems
    });
    setLoading(false);
  };

  const handleGenerateTicket = async () => {
    if (!ticketRef.current) return;
    try {
      const canvas = await html2canvas(ticketRef.current, { backgroundColor: COLORS.CREAM });
      const link = document.createElement('a');
      link.download = `yuanware_luxe_${Date.now()}.png`;
      link.href = canvas.toDataURL();
      link.click();
    } catch (err) {
      console.error('Failed to generate ticket', err);
    }
  };

  const sendMessage = async () => {
    if (!userInput.trim() || !analysis) return;
    const userMsg: ChatMessage = { role: 'user', content: userInput };
    const newHistory = [...chatHistory, userMsg];
    setChatHistory(newHistory);
    setUserInput('');
    setChatLoading(true);
    try {
      const aiResponse = await getStrategicAnalysis(analysis, newHistory);
      setChatHistory([...newHistory, { role: 'model', content: aiResponse }]);
    } catch (err) {
      console.error(err);
    } finally {
      setChatLoading(false);
    }
  };

  const resetAll = () => {
    setAnalysis(null);
    setChatHistory([]);
    setItems([{ id: '1', name: '', priceYuan: 0, quantity: 1 }]);
    setFreight(0);
    setTax(0);
  };

  return (
    <div className="min-h-screen flex flex-col items-center p-6 md:p-12 space-y-12">
      {/* Header */}
      <header className="w-full max-w-6xl flex flex-col items-center justify-center py-10 border-b border-black/10">
        <h1 className="text-4xl md:text-6xl font-serif font-light tracking-widest uppercase">
          Yuanware <span className="font-bold">Luxe</span>
        </h1>
        <div className="flex items-center gap-4 mt-4">
          <div className="h-[1px] w-12 bg-black/30"></div>
          <p className="text-xs uppercase tracking-[0.4em] font-light">Suite de Importação de Elite</p>
          <div className="h-[1px] w-12 bg-black/30"></div>
        </div>
      </header>

      <main className="w-full max-w-6xl grid grid-cols-1 lg:grid-cols-12 gap-12">

        {/* Input Side */}
        <div className="lg:col-span-5 space-y-8">
          <section className="bg-white/40 p-8 border border-black/10 luxury-shadow relative">
            <div className="absolute top-0 left-0 w-1 h-full bg-black"></div>
            <h2 className="text-sm font-bold tracking-[0.2em] mb-8 flex items-center gap-3 uppercase">
              01. Inventário de Carga
            </h2>

            <div className="space-y-6">
              {items.map((item, idx) => (
                <div key={item.id} className="grid grid-cols-12 gap-4 pb-6 border-b border-black/5 last:border-0">
                  <div className="col-span-12 md:col-span-6">
                    <label className="text-[10px] text-zinc-400 font-bold uppercase tracking-wider mb-1 block">Modelo / Item</label>
                    <input
                      type="text"
                      placeholder="NOME DO PRODUTO"
                      className="w-full bg-transparent border-b border-black/20 pb-1 text-sm font-medium focus:border-black transition-colors"
                      value={item.name}
                      onChange={(e) => updateItem(item.id, 'name', e.target.value)}
                    />
                  </div>
                  <div className="col-span-5 md:col-span-3">
                    <label className="text-[10px] text-zinc-400 font-bold uppercase tracking-wider mb-1 block">Preço (¥)</label>
                    <input
                      type="number"
                      placeholder="0.00"
                      className="w-full bg-transparent border-b border-black/20 pb-1 text-sm font-mono focus:border-black transition-colors"
                      value={item.priceYuan || ''}
                      onChange={(e) => updateItem(item.id, 'priceYuan', Number(e.target.value))}
                    />
                  </div>
                  <div className="col-span-4 md:col-span-2">
                    <label className="text-[10px] text-zinc-400 font-bold uppercase tracking-wider mb-1 block">Qtd</label>
                    <input
                      type="number"
                      placeholder="1"
                      className="w-full bg-transparent border-b border-black/20 pb-1 text-sm font-mono focus:border-black transition-colors"
                      value={item.quantity || ''}
                      onChange={(e) => updateItem(item.id, 'quantity', Number(e.target.value))}
                    />
                  </div>
                  <div className="col-span-3 md:col-span-1 flex items-end">
                    <button 
                      onClick={() => removeItem(item.id)}
                      className="text-zinc-300 hover:text-red-600 transition-colors p-1"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                </div>
              ))}
            </div>

            <button 
              onClick={addItem}
              className="mt-8 w-full py-3 border border-black text-[10px] font-bold tracking-[0.2em] uppercase hover:bg-black hover:text-white transition-all flex items-center justify-center gap-2"
            >
              <Plus size={14} /> Novo Item
            </button>
          </section>

          {/* Logistics */}
          <section className="bg-white/40 p-8 border border-black/10 luxury-shadow relative">
             <div className="absolute top-0 left-0 w-1 h-full bg-[#D0021B]"></div>
             <h2 className="text-sm font-bold tracking-[0.2em] mb-8 flex items-center gap-3 uppercase">
              02. Logística & Taxas
            </h2>
             <div className="grid grid-cols-2 gap-8">
                <div>
                  <label className="text-[10px] text-zinc-400 font-bold uppercase tracking-wider mb-2 block">Custo de Frete (¥)</label>
                  <input
                    type="number"
                    className="w-full bg-transparent border-b border-black/20 pb-2 text-lg font-mono focus:border-black"
                    value={freight || ''}
                    onChange={(e) => setFreight(Number(e.target.value))}
                  />
                </div>
                <div>
                  <label className="text-[10px] text-zinc-400 font-bold uppercase tracking-wider mb-2 block">Cotação Spread (R$)</label>
                  <input
                    type="number"
                    step="0.01"
                    className="w-full bg-transparent border-b border-black/20 pb-2 text-lg font-mono focus:border-black"
                    value={rate}
                    onChange={(e) => setRate(Number(e.target.value))}
                  />
                </div>
                <div className="col-span-2">
                  <label className="text-[10px] text-zinc-400 font-bold uppercase tracking-wider mb-2 block">Desembaraço / Taxas (R$)</label>
                  <input
                    type="number"
                    className="w-full bg-transparent border-b border-black/20 pb-2 text-lg font-mono focus:border-black"
                    value={tax || ''}
                    onChange={(e) => setTax(Number(e.target.value))}
                  />
                </div>
             </div>

             <button 
              onClick={processData}
              disabled={loading}
              className="mt-10 w-full luxury-button py-5 text-sm font-black tracking-[0.3em] uppercase flex items-center justify-center gap-4"
            >
              Processar Análise <ArrowRight size={18} />
            </button>
          </section>
        </div>

        {/* Output Side */}
        <div className="lg:col-span-7 space-y-10">
          {analysis ? (
            <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-700">

              {/* Verdict Card */}
              <div className={`p-10 border border-black flex flex-col md:flex-row items-center justify-between relative overflow-hidden bg-white shadow-xl`}>
                <div className="absolute top-0 right-0 w-32 h-32 bg-black/5 -mr-16 -mt-16 rotate-45"></div>
                <div className="flex items-center gap-8 z-10">
                  <div className="p-4 border border-black">
                    {analysis.verdict === 'GEM' && <Diamond size={40} className="text-black" />}
                    {analysis.verdict === 'HEALTHY' && <ShieldCheck size={40} className="text-black" />}
                    {analysis.verdict === 'RISKY' && <AlertTriangle size={40} className="text-red" />}
                  </div>
                  <div>
                    <h3 className="text-2xl font-serif italic mb-1">
                      {analysis.verdict === 'GEM' ? 'Oportunidade de Ouro' : 
                       analysis.verdict === 'HEALTHY' ? 'Margem Segura' : 
                       'Risco Detectado'}
                    </h3>
                    <p className="text-[10px] text-zinc-400 font-bold uppercase tracking-widest">
                      {analysis.verdict === 'RISKY' ? '⚠️ Reavaliar Investimento' : '✓ Aprovado para Importação'}
                    </p>
                  </div>
                </div>
                <div className="mt-6 md:mt-0 text-right z-10">
                  <p className="text-4xl font-bold font-mono tracking-tighter">{analysis.roi.toFixed(1)}%</p>
                  <p className="text-[10px] font-bold text-black uppercase tracking-[0.2em]">ROI Projetado</p>
                </div>
              </div>

              {/* Summary Cards */}
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {[
                  { label: 'Investimento', value: analysis.totalInvestmentBRL },
                  { label: 'Faturamento', value: analysis.totalRevenueBRL },
                  { label: 'Lucro Líquido', value: analysis.totalProfitBRL, accent: true }
                ].map((stat, i) => (
                  <div key={i} className="bg-white border border-black/10 p-6 shadow-sm">
                    <p className="text-[10px] text-zinc-400 font-bold uppercase tracking-wider mb-2">{stat.label}</p>
                    <p className={`text-xl font-bold font-mono ${stat.accent ? 'text-red' : 'text-black'}`}>
                      R$ {stat.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                    </p>
                  </div>
                ))}
              </div>

              {/* Detailed Table */}
              <div className="bg-white border border-black/10 shadow-lg overflow-hidden">
                <div className="p-4 border-b border-black/5 bg-zinc-50">
                  <p className="text-[10px] font-bold tracking-[0.2em] uppercase">Detalhamento por Item</p>
                </div>
                <div className="overflow-x-auto">
                  <table className="w-full text-left">
                    <thead className="bg-white border-b border-black/10">
                      <tr className="text-[10px] text-zinc-400 uppercase font-bold tracking-widest">
                        <th className="p-5">Produto</th>
                        <th className="p-5">Qtd</th>
                        <th className="p-5">Custo Un.</th>
                        <th className="p-5">Preço Luxo</th>
                        <th className="p-5">Lucro</th>
                      </tr>
                    </thead>
                    <tbody className="text-xs">
                      {analysis.items.map((item, i) => (
                        <tr key={i} className="border-b border-black/5 hover:bg-zinc-50 transition-colors">
                          <td className="p-5 font-bold uppercase tracking-tighter">{item.name || 'ANONYMOUS'}</td>
                          <td className="p-5 font-mono">{item.quantity}</td>
                          <td className="p-5 text-zinc-500 font-mono">R$ {item.totalCostBRL.toFixed(2)}</td>
                          <td className="p-5 font-bold font-mono text-black">R$ {item.suggestedPriceBRL.toFixed(2)}</td>
                          <td className="p-5 font-bold font-mono text-red">R$ {item.profitBRL.toFixed(2)}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>

              {/* AI Chat Section */}
              <div className="bg-white border border-black shadow-lg overflow-hidden flex flex-col">
                <div className="bg-black text-white p-4 flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <Bot size={16} />
                    <span className="text-[10px] font-bold uppercase tracking-[0.3em]">YUANWARE CONCIERGE AI</span>
                  </div>
                  <div className="w-2 h-2 rounded-full bg-red-500 animate-pulse"></div>
                </div>
                <div className="h-72 overflow-y-auto p-6 space-y-6 text-sm">
                  {chatHistory.length === 0 && (
                    <div className="h-full flex flex-col items-center justify-center text-zinc-300 text-center space-y-4">
                      <MessageSquare size={40} strokeWidth={1} />
                      <p className="text-xs uppercase tracking-widest font-light">Solicite uma consultoria estratégica personalizada sobre este lote.</p>
                    </div>
                  )}
                  {chatHistory.map((msg, i) => (
                    <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                      <div className={`max-w-[85%] p-4 leading-relaxed ${
                        msg.role === 'user' 
                          ? 'bg-zinc-100 text-black border border-black/5 font-medium' 
                          : 'bg-white border-l-4 border-black text-black shadow-sm italic'
                      }`}>
                        {msg.content}
                      </div>
                    </div>
                  ))}
                  {chatLoading && <div className="text-zinc-400 text-xs italic font-light">O Concierge está analisando as métricas de mercado...</div>}
                </div>
                <div className="p-4 border-t border-black/5 flex gap-4 bg-zinc-50">
                  <input
                    type="text"
                    placeholder="Escrva sua dúvida estratégica..."
                    className="flex-1 bg-transparent border-b border-black/10 p-2 text-sm focus:border-black transition-colors"
                    value={userInput}
                    onChange={(e) => setUserInput(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && sendMessage()}
                  />
                  <button 
                    onClick={sendMessage}
                    disabled={chatLoading}
                    className="bg-black text-white p-3 hover:bg-zinc-800 transition-colors"
                  >
                    <Send size={16} />
                  </button>
                </div>
              </div>

              {/* Footer Actions */}
              <div className="flex flex-col md:flex-row gap-6 pt-6">
                <button 
                  onClick={handleGenerateTicket}
                  className="flex-1 border-2 border-black bg-white text-black font-bold py-5 text-sm uppercase tracking-[0.2em] hover:bg-black hover:text-white transition-all flex items-center justify-center gap-4 shadow-xl"
                >
                  <Receipt size={18} /> Exportar Ticket de Carga
                </button>
                <button 
                  onClick={resetAll}
                  className="bg-transparent text-zinc-400 font-bold px-8 py-5 text-[10px] uppercase tracking-widest hover:text-red transition-all flex items-center justify-center gap-2"
                >
                  <RotateCcw size={14} /> Novo Cálculo
                </button>
              </div>

            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center text-zinc-200 text-center space-y-8 py-20">
              <div className="relative">
                <LayoutDashboard size={100} strokeWidth={0.5} />
                <div className="absolute inset-0 flex items-center justify-center">
                   <div className="w-16 h-16 border-t-2 border-black/10 rounded-full animate-spin"></div>
                </div>
              </div>
              <div>
                <h3 className="text-xl font-serif italic text-zinc-400">Aguardando Parâmetros</h3>
                <p className="text-[10px] font-bold uppercase tracking-[0.3em] mt-2 text-zinc-300">Complete os passos 01 e 02 ao lado</p>
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Hidden Ticket Template - Styled for Luxe */}
      <div style={{ position: 'absolute', left: '-9999px', top: '0' }}>
        <div 
          ref={ticketRef} 
          className="w-[500px] bg-[#FDFCF5] p-12 border-[10px] border-black flex flex-col items-center text-black"
        >
          <div className="w-full text-center border-b-2 border-black pb-10 mb-10">
            <h1 className="text-4xl font-serif font-light tracking-[0.2em] mb-2 uppercase">YUANWARE <span className="font-bold">LUXE</span></h1>
            <p className="text-[10px] tracking-[0.5em] font-bold uppercase opacity-50">Logística de Alto Padrão</p>
          </div>

          <div className="w-full space-y-8 font-mono">
            <div className="flex justify-between items-end border-b border-black/10 pb-4">
              <span className="text-[10px] font-bold opacity-40 uppercase tracking-widest">Investimento</span>
              <span className="text-2xl font-bold">R$ {analysis?.totalInvestmentBRL.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
            </div>
            <div className="flex justify-between items-end border-b border-black/10 pb-4">
              <span className="text-[10px] font-bold opacity-40 uppercase tracking-widest">Lucro Previsto</span>
              <span className="text-2xl font-bold text-[#D0021B]">R$ {analysis?.totalProfitBRL.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
            </div>
            <div className="flex justify-between items-end border-b border-black/10 pb-4">
              <span className="text-[10px] font-bold opacity-40 uppercase tracking-widest">ROI da Operação</span>
              <span className="text-2xl font-bold">{analysis?.roi.toFixed(1)}%</span>
            </div>
          </div>

          <div className="mt-16 w-full text-center space-y-6">
            <div className="py-4 border-y-2 border-black">
               <p className="text-sm font-serif italic font-medium tracking-widest">
                {analysis?.verdict === 'GEM' ? 'CERTIFICADO DE ALTA RENTABILIDADE' : 'OPERACIONAL APROVADO'}
               </p>
            </div>
            <p className="text-[10px] tracking-[0.4em] font-black uppercase">🔥 powered by yuanware luxe</p>
            <p className="text-[8px] opacity-40 font-mono">{new Date().toLocaleString('pt-BR').toUpperCase()}</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo, useRef } from 'react';
import { Plus, Trash2, LayoutDashboard, Calculator, Receipt, RotateCcw, MessageSquare, Send, Bot, AlertTriangle, ShieldCheck, Diamond, ArrowRight } from 'lucide-react';
import html2canvas from 'html2canvas';
import { ProductItem, AnalysisResult, CalculatedItem, ChatMessage } from './types';
import { COLORS, DEFAULT_EXCHANGE_RATE } from './constants';
import { getStrategicAnalysis } from './services/geminiService';

const App: React.FC = () => {
  const [items, setItems] = useState<ProductItem[]>([
    { id: '1', name: '', priceYuan: 0, quantity: 1 }
  ]);
  const [freight, setFreight] = useState<number>(0);
  const [tax, setTax] = useState<number>(0);
  const [rate, setRate] = useState<number>(DEFAULT_EXCHANGE_RATE);
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [userInput, setUserInput] = useState('');
  const [chatLoading, setChatLoading] = useState(false);

  const ticketRef = useRef<HTMLDivElement>(null);

  const addItem = () => {
    setItems([...items, { id: Math.random().toString(36).substr(2, 9), name: '', priceYuan: 0, quantity: 1 }]);
  };

  const removeItem = (id: string) => {
    if (items.length > 1) {
      setItems(items.filter(item => item.id !== id));
    }
  };

  const updateItem = (id: string, field: keyof ProductItem, value: string | number) => {
    setItems(items.map(item => item.id === id ? { ...item, [field]: value } : item));
  };

  const processRounding = (price: number): number => {
    const ceilVal = Math.ceil(price);
    const lastDigit = ceilVal % 10;
    if (lastDigit === 0) return ceilVal;
    if (lastDigit < 7) return Math.floor(ceilVal / 10) * 10 + 7;
    return Math.ceil(ceilVal / 10) * 10;
  };

  const processData = () => {
    setLoading(true);
    const totalItemsValueYuan = items.reduce((acc, item) => acc + (item.priceYuan * item.quantity), 0);

    const calculatedItems: CalculatedItem[] = items.map(item => {
      const itemTotalPriceYuan = item.priceYuan * item.quantity;
      const weight = totalItemsValueYuan > 0 ? (itemTotalPriceYuan / totalItemsValueYuan) : 0;

      const itemFreightYuan = weight * freight;
      const itemTaxBRL = weight * tax;

      const itemCostBRL = ((item.priceYuan + (itemFreightYuan / item.quantity)) * rate) + (itemTaxBRL / item.quantity);
      const suggestedPrice = processRounding(itemCostBRL * 2);
      const profit = suggestedPrice - itemCostBRL;

      return {
        ...item,
        distributedFreightBRL: (itemFreightYuan / item.quantity) * rate,
        distributedTaxBRL: itemTaxBRL / item.quantity,
        totalCostBRL: itemCostBRL,
        suggestedPriceBRL: suggestedPrice,
        profitBRL: profit
      };
    });

    const totalInvestment = calculatedItems.reduce((acc, item) => acc + (item.totalCostBRL * item.quantity), 0);
    const totalRevenue = calculatedItems.reduce((acc, item) => acc + (item.suggestedPriceBRL * item.quantity), 0);
    const totalProfit = totalRevenue - totalInvestment;
    const roi = totalInvestment > 0 ? (totalProfit / totalInvestment) * 100 : 0;

    let verdict: 'GEM' | 'HEALTHY' | 'RISKY' = 'RISKY';
    if (roi > 100) verdict = 'GEM';
    else if (roi >= 50) verdict = 'HEALTHY';

    setAnalysis({
      totalInvestmentBRL: totalInvestment,
      totalRevenueBRL: totalRevenue,
      totalProfitBRL: totalProfit,
      roi,
      verdict,
      items: calculatedItems
    });
    setLoading(false);
  };

  const handleGenerateTicket = async () => {
    if (!ticketRef.current) return;
    try {
      const canvas = await html2canvas(ticketRef.current, { 
        backgroundColor: COLORS.CREAM,
        scale: 2,
        borderRadius: 40
      });
      const link = document.createElement('a');
      link.download = `yuanware_luxury_concierge_${Date.now()}.png`;
      link.href = canvas.toDataURL();
      link.click();
    } catch (err) {
      console.error('Failed to generate ticket', err);
    }
  };

  const sendMessage = async () => {
    if (!userInput.trim() || !analysis) return;
    const userMsg: ChatMessage = { role: 'user', content: userInput };
    const newHistory = [...chatHistory, userMsg];
    setChatHistory(newHistory);
    setUserInput('');
    setChatLoading(true);
    try {
      const aiResponse = await getStrategicAnalysis(analysis, newHistory);
      setChatHistory([...newHistory, { role: 'model', content: aiResponse }]);
    } catch (err) {
      console.error(err);
    } finally {
      setChatLoading(false);
    }
  };

  const resetAll = () => {
    setAnalysis(null);
    setChatHistory([]);
    setItems([{ id: '1', name: '', priceYuan: 0, quantity: 1 }]);
    setFreight(0);
    setTax(0);
  };

  return (
    <div className="min-h-screen flex flex-col items-center p-6 md:p-12 space-y-16">
      {/* Header */}
      <header className="w-full max-w-6xl flex flex-col items-center justify-center py-12 fade-in-up">
        <h1 className="text-5xl md:text-7xl font-serif font-light tracking-widest uppercase text-center">
          Yuanware <span className="font-bold">Luxe</span>
        </h1>
        <div className="flex items-center gap-6 mt-6">
          <div className="h-[1px] w-16 bg-black/10"></div>
