                  ))}
                  {chatLoading && <div className="text-zinc-400 text-[11px] italic font-light px-6 animate-pulse">Processando métricas globais...</div>}
                </div>
                <div className="p-6 border-t border-black/5 flex gap-4 bg-zinc-50/50">
                  <input
