                <div className="h-80 overflow-y-auto p-8 space-y-8 text-sm">
                  {chatHistory.length === 0 && (
                    <div className="h-full flex flex-col items-center justify-center text-zinc-200 text-center space-y-4">
                      <MessageSquare size={48} strokeWidth={1} />
                      <p className="text-[10px] uppercase tracking-[0.2em] font-medium max-w-xs">Consultoria estratégica de mercado disponível agora.</p>
                    </div>
                  )}
                  {chatHistory.map((msg, i) => (
                    <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                      <div className={`max-w-[85%] px-6 py-4 rounded-[1.5rem] leading-relaxed ${
                        msg.role === 'user' 
                          ? 'bg-zinc-100 text-black font-medium rounded-tr-none shadow-sm' 
                          : 'bg-white border border-black/10 text-black italic rounded-tl-none shadow-sm'
                      }`}>
                        {msg.content}
                      </div>
                    </div>
                  ))}
                  {chatLoading && <div className="text-zinc-400 text-[11px] italic font-light px-6 animate-pulse">Analisando o lote com dados do mercado...</div>}
                </div>
                <div className="p-6 border-t border-black/5 flex gap-4 bg-zinc-50/50">
                  <input
                    type="text"
                    placeholder="Pergunte sobre rentabilidade ou estratégia..."
                    className="flex-1 bg-white border-none px-6 py-4 text-sm focus:ring-2 ring-black/5 rounded-full shadow-inner transition-all"
                    value={userInput}
                    onChange={(e) => setUserInput(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && sendMessage()}
                  />
                  <button 
                    onClick={sendMessage}
                    disabled={chatLoading}
                    className="bg-black text-white p-4 rounded-full hover:scale-110 transition-transform shadow-lg"
                  >
                    <Send size={18} />
                  </button>
                </div>
              </div>

              {/* Action Bar */}
              <div className="flex flex-col md:flex-row gap-8 pt-8 pb-12">
                <button 
                  onClick={handleGenerateTicket}
                  className="flex-1 rounded-full border-2 border-black bg-white text-black font-black py-6 text-xs uppercase tracking-[0.3em] hover:bg-black hover:text-white transition-all flex items-center justify-center gap-4 shadow-2xl"
                >
                  <Receipt size={20} /> Exportar Ticket de Operação
                </button>
                <button 
                  onClick={resetAll}
                  className="px-10 py-6 rounded-full bg-zinc-50 text-zinc-400 font-bold text-[10px] uppercase tracking-[0.3em] hover:text-red transition-all flex items-center justify-center gap-3"
                >
