import React, { useState, useCallback, useMemo, useRef, memo } from 'react';
import { Plus, Trash2, LayoutDashboard, Calculator, Receipt, RotateCcw, MessageSquare, Send, Bot, AlertTriangle, ShieldCheck, Diamond, ArrowRight } from 'lucide-react';
import html2canvas from 'html2canvas';
import { ProductItem, AnalysisResult, CalculatedItem, ChatMessage } from './types';
import { COLORS, DEFAULT_EXCHANGE_RATE } from './constants';
import { getStrategicAnalysis } from './services/geminiService';

// Memoized Item Row to prevent re-rendering the whole list on every keystroke
const ItemRow = memo(({ 
  item, 
  onUpdate, 
  onRemove 
}: { 
  item: ProductItem; 
  onUpdate: (id: string, field: keyof ProductItem, value: string | number) => void;
  onRemove: (id: string) => void;
}) => {
  return (
    <div className="grid grid-cols-12 gap-4 pb-8 border-b border-black/5 last:border-0 last:pb-0 animate-in fade-in slide-in-from-left-2 duration-300">
      <div className="col-span-12 md:col-span-5">
        <label className="text-[9px] text-zinc-400 font-bold uppercase tracking-widest mb-2 block">Descrição</label>
        <input
          type="text"
          placeholder="Modelo ou Lote"
          className="w-full bg-zinc-50 border-none px-4 py-3 text-sm font-medium focus:ring-2 ring-black/5 transition-all rounded-xl"
          value={item.name}
          onChange={(e) => onUpdate(item.id, 'name', e.target.value)}
        />
      </div>
      <div className="col-span-6 md:col-span-3">
        <label className="text-[9px] text-zinc-400 font-bold uppercase tracking-widest mb-2 block">Preço (¥)</label>
        <input
          type="number"
          placeholder="0"
          className="w-full bg-zinc-50 border-none px-4 py-3 text-sm font-mono focus:ring-2 ring-black/5 rounded-xl"
          value={item.priceYuan || ''}
          onChange={(e) => onUpdate(item.id, 'priceYuan', Number(e.target.value))}
        />
      </div>
      <div className="col-span-4 md:col-span-3">
        <label className="text-[9px] text-zinc-400 font-bold uppercase tracking-widest mb-2 block">Qtd.</label>
        <input
          type="number"
          placeholder="1"
          className="w-full bg-zinc-50 border-none px-4 py-3 text-sm font-mono focus:ring-2 ring-black/5 rounded-xl text-center"
          value={item.quantity || ''}
          onChange={(e) => onUpdate(item.id, 'quantity', Number(e.target.value))}
        />
      </div>
      <div className="col-span-2 md:col-span-1 flex items-end justify-center">
        <button 
          onClick={() => onRemove(item.id)}
          className="text-zinc-300 hover:text-red transition-all p-2 hover:bg-red/5 rounded-full mb-1"
          aria-label="Remover item"
        >
          <Trash2 size={18} />
        </button>
      </div>
    </div>
  );
});

ItemRow.displayName = 'ItemRow';

const App: React.FC = () => {
  const [items, setItems] = useState<ProductItem[]>([
    { id: '1', name: '', priceYuan: 0, quantity: 1 }
  ]);
  const [freight, setFreight] = useState<number>(0);
  const [tax, setTax] = useState<number>(0);
  const [rate, setRate] = useState<number>(DEFAULT_EXCHANGE_RATE);
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [userInput, setUserInput] = useState('');
  const [chatLoading, setChatLoading] = useState(false);

  const ticketRef = useRef<HTMLDivElement>(null);

  const addItem = useCallback(() => {
    setItems(prev => [...prev, { id: Math.random().toString(36).substr(2, 9), name: '', priceYuan: 0, quantity: 1 }]);
  }, []);

  const removeItem = useCallback((id: string) => {
    setItems(prev => prev.length > 1 ? prev.filter(item => item.id !== id) : prev);
  }, []);

  const updateItem = useCallback((id: string, field: keyof ProductItem, value: string | number) => {
    setItems(prev => prev.map(item => item.id === id ? { ...item, [field]: value } : item));
  }, []);

  const processRounding = (price: number): number => {
    const ceilVal = Math.ceil(price);
    const lastDigit = ceilVal % 10;
    if (lastDigit === 0) return ceilVal;
    if (lastDigit < 7) return Math.floor(ceilVal / 10) * 10 + 7;
    return Math.ceil(ceilVal / 10) * 10;
  };

  const processData = useCallback(() => {
    setLoading(true);

    // Performance improvement: Single pass to calculate total Yuan and then another pass to compute details + totals
    // 1. Calculate total Yuan value of products (Price * Qty)
    let totalItemsValueYuan = 0;
    for (let i = 0; i < items.length; i++) {
      totalItemsValueYuan += (items[i].priceYuan * items[i].quantity);
    }

    let totalInvestment = 0;
    let totalRevenue = 0;

    const calculatedItems: CalculatedItem[] = items.map(item => {
      const itemTotalPriceYuan = item.priceYuan * item.quantity;

      // Proportional weight based on product cost (Smart Dissolver)
      const weight = totalItemsValueYuan > 0 ? (itemTotalPriceYuan / totalItemsValueYuan) : 0;

      const itemFreightYuan = weight * freight;
      const itemTaxBRL = weight * tax;

      // Conversion logic: (PriceYuan + ProportionalFreightYuan) * rate + ProportionalTaxBRL
      const totalProductInvestmentBRL = (itemTotalPriceYuan + itemFreightYuan) * rate + itemTaxBRL;

      // Unit cost calculation
      const unitCostBRL = item.quantity > 0 ? totalProductInvestmentBRL / item.quantity : 0;

      // Suggestion: 100% margin + rounding psychological (ends in 7 or 0)
      const suggestedPrice = processRounding(unitCostBRL * 2);
      const profit = suggestedPrice - unitCostBRL;

      // Accumulate totals during mapping to avoid additional reduce calls
      totalInvestment += (unitCostBRL * item.quantity);
      totalRevenue += (suggestedPrice * item.quantity);

      return {
        ...item,
        distributedFreightBRL: (itemFreightYuan / item.quantity) * rate,
        distributedTaxBRL: itemTaxBRL / item.quantity,
        totalCostBRL: unitCostBRL,
        suggestedPriceBRL: suggestedPrice,
        profitBRL: profit
      };
    });

    const totalProfit = totalRevenue - totalInvestment;
    const roi = totalInvestment > 0 ? (totalProfit / totalInvestment) * 100 : 0;

    let verdict: 'GEM' | 'HEALTHY' | 'RISKY' = 'RISKY';
    if (roi > 100) verdict = 'GEM';
    else if (roi >= 50) verdict = 'HEALTHY';

    setAnalysis({
      totalInvestmentBRL: totalInvestment,
      totalRevenueBRL: totalRevenue,
      totalProfitBRL: totalProfit,
      roi,
      verdict,
      items: calculatedItems
    });
    setLoading(false);
  }, [items, freight, tax, rate]);

  const handleGenerateTicket = async () => {
    if (!ticketRef.current) return;
    try {
      const canvas = await html2canvas(ticketRef.current, { 
        backgroundColor: COLORS.CREAM,
        scale: 2,
        borderRadius: 40
      });
      const link = document.createElement('a');
      link.download = `yuanwarecalculator_ticket_${Date.now()}.png`;
      link.href = canvas.toDataURL();
      link.click();
    } catch (err) {
      console.error('Failed to generate ticket', err);
    }
  };

  const sendMessage = async () => {
    if (!userInput.trim() || !analysis) return;
    const userMsg: ChatMessage = { role: 'user', content: userInput };
    const newHistory = [...chatHistory, userMsg];
    setChatHistory(newHistory);
    setUserInput('');
    setChatLoading(true);
    try {
      const aiResponse = await getStrategicAnalysis(analysis, newHistory);
      setChatHistory([...newHistory, { role: 'model', content: aiResponse }]);
    } catch (err) {
      console.error(err);
    } finally {
      setChatLoading(false);
    }
  };

  const resetAll = useCallback(() => {
    setAnalysis(null);
    setChatHistory([]);
    setItems([{ id: '1', name: '', priceYuan: 0, quantity: 1 }]);
    setFreight(0);
    setTax(0);
  }, []);

  return (
    <div className="min-h-screen flex flex-col items-center p-6 md:p-12 space-y-16">
      {/* Header */}
      <header className="w-full max-w-6xl flex flex-col items-center justify-center py-12 fade-in-up">
        <h1 className="text-4xl md:text-6xl font-serif font-light tracking-widest uppercase text-center lowercase">
          yuanware<span className="font-bold">calculator</span>
        </h1>
        <div className="flex items-center gap-6 mt-6">
          <div className="h-[1px] w-16 bg-black/10"></div>
          <p className="text-[10px] uppercase tracking-[0.6em] font-medium text-zinc-400">Elite Logistics Intelligence</p>
          <div className="h-[1px] w-16 bg-black/10"></div>
        </div>
      </header>

      <main className="w-full max-w-6xl grid grid-cols-1 lg:grid-cols-12 gap-12 items-start">

        {/* Input Side */}
        <div className="lg:col-span-5 space-y-10 fade-in-up">
          <section className="bg-white p-10 rounded-[2.5rem] luxury-shadow border border-black/5">
            <h2 className="text-[11px] font-black tracking-[0.3em] mb-10 flex items-center gap-4 uppercase text-zinc-400">
              <span className="w-8 h-[1px] bg-black/20"></span>
              01. Inventário de Carga (¥)
            </h2>

            <div className="space-y-8">
              {items.map((item) => (
                <ItemRow 
                  key={item.id} 
                  item={item} 
                  onUpdate={updateItem} 
                  onRemove={removeItem} 
                />
              ))}
            </div>

            <button 
              onClick={addItem}
              className="mt-10 w-full py-4 rounded-full border border-black/10 text-[10px] font-bold tracking-[0.2em] uppercase hover:bg-black hover:text-white transition-all flex items-center justify-center gap-3"
            >
              <Plus size={14} /> Novo Item
            </button>
          </section>

          {/* Logistics */}
          <section className="bg-white p-10 rounded-[2.5rem] luxury-shadow border border-black/5">
             <h2 className="text-[11px] font-black tracking-[0.3em] mb-10 flex items-center gap-4 uppercase text-zinc-400">
               <span className="w-8 h-[1px] bg-red/30"></span>
               02. Logística Estratégica
            </h2>
             <div className="grid grid-cols-2 gap-8">
                <div>
                  <label className="text-[9px] text-zinc-400 font-bold uppercase tracking-widest mb-3 block">Frete Total (¥)</label>
                  <input
                    type="number"
                    className="w-full bg-zinc-50 border-none p-4 text-xl font-mono rounded-2xl"
                    value={freight || ''}
                    onChange={(e) => setFreight(Number(e.target.value))}
                  />
                </div>
                <div>
                  <label className="text-[9px] text-zinc-400 font-bold uppercase tracking-widest mb-3 block">Spread R$</label>
                  <input
                    type="number"
                    step="0.01"
                    className="w-full bg-zinc-50 border-none p-4 text-xl font-mono rounded-2xl"
                    value={rate}
                    onChange={(e) => setRate(Number(e.target.value))}
                  />
                </div>
                <div className="col-span-2">
                  <label className="text-[9px] text-zinc-400 font-bold uppercase tracking-widest mb-3 block">Taxação Alfandegária (R$)</label>
                  <input
                    type="number"
                    placeholder="Total de taxas pagas"
