                </button>
                <button 
                  onClick={resetAll}
                  className="px-10 py-6 rounded-full bg-zinc-50 text-zinc-400 font-bold text-[10px] uppercase tracking-[0.3em] hover:text-red transition-all flex items-center justify-center gap-3 active:scale-95"
                >
